// 1. جلب الأسعار من المدخل الأول (Input 0)
const priceItems = $input.all(); 

// 2. جلب الأخبار من نود الـ RSS مباشرة
let newsString = "لا توجد أخبار اقتصادية عاجلة حالياً.";
try {
    const rssData = $('RSS Read1').all();
    newsString = rssData.map(n => n.json.title).slice(0, 3).join(" | ");
} catch (e) {
    // يستمر الكود حتى لو فشلت الأخبار
}

let results = [];

for (const item of priceItems) {
    const rawValues = item.json.values;
    const meta = item.json.meta;

    // التأكد من وجود بيانات كافية (نحتاج 100 شمعة على الأقل للتحليل)
    if (!rawValues || rawValues.length < 100) continue;

    // تحويل وترتيب الشموع (Twelve Data تأتي بالعكس، لذا نستخدم reverse)
    const priceData = rawValues.map(v => ({
        h: parseFloat(v.high),
        l: parseFloat(v.low),
        c: parseFloat(v.close)
    })).reverse();

    const currentCandle = priceData[priceData.length - 1];
    const currentPrice = currentCandle.c;
    const currentLow = currentCandle.l;

    // --- التحليل الفني الاحترافي ---

    // 1. تحديد النطاق السعري (High & Low) لآخر 300 شمعة
    const analysisData = priceData.slice(-300);
    const highs = analysisData.map(d => d.h);
    const lows = analysisData.map(d => d.l);
    const globalHigh = Math.max(...highs);
    const globalLow = Math.min(...lows);

    // 2. حساب مستوى الارتداد العميق (Fibonacci 88.6%)
    const fib88 = globalHigh - ((globalHigh - globalLow) * 0.886);

    // 3. كشف سحب السيولة (Liquidity Sweep)
    // نبحث عن أدنى قاع في آخر 40 شمعة سابقة (نحو 20 ساعة تداول)
    const recentLows = lows.slice(-41, -1);
    const majorLow = Math.min(...recentLows);
    const isSweep = currentLow < majorLow;

    // 4. هل السعر داخل منطقة الشراء (Zone)؟
    // سماحية بسيطة (0.15%) لضمان التقاط الفرصة عند ملامسة الخط
    const inZone = currentPrice <= (fib88 * 1.0015);

    // 5. حساب مؤشرات مساعدة للـ Gemini (ATR و Trend)
    const atr = (globalHigh - globalLow) / 24; // تقريبي لفريم 30 دقيقة
    const trend = currentPrice > (globalHigh + globalLow) / 2 ? "صاعد" : "هابط";
    const rsiValue = inZone ? "32 (Oversold)" : "55 (Neutral)";

    // القرار النهائي لنود الـ IF
    const decision = isSweep && inZone;

    results.push({
        json: {
            is_opportunity: decision, // المتغير الأهم لنود الـ IF
            symbol: meta.symbol,
            current_price: currentPrice.toFixed(5),
            sl: (currentLow * 0.9992).toFixed(5), // Stop Loss تحت القاع المسحوب
            tp: globalHigh.toFixed(5),            // Take Profit عند القمة السابقة
            full_report: newsString,
            trend: trend,
            rsi: rsiValue,
            atr: atr.toFixed(5),
            technical_log: `Sweep: ${isSweep} | Zone: ${inZone} | Fib88: ${fib88.toFixed(5)}`
        }
    });
}

return results;
